'use client';

import type { WorkspaceMember } from '@/lib/usage/members';

/**
 * Renders the per-member quota table on the AI Usage dashboard.
 * Each member has a monthly token quota we display formatted with thousands
 * separators, alongside how much of it they've used this billing period.
 */
export function MemberQuotaTable({ members }: { members: WorkspaceMember[] }) {
  return (
    <table className="usage-table">
      <thead>
        <tr>
          <th>Member</th>
          <th>Used this month</th>
          <th>Monthly quota</th>
          <th>Remaining</th>
        </tr>
      </thead>
      <tbody>
        {members.map((member) => {
          // monthlyQuota is a number per the WorkspaceMember type, so we can
          // format and do arithmetic on it directly.
          const quota = member.monthlyQuota.toLocaleString();
          const remaining = (member.monthlyQuota - member.tokensUsed).toLocaleString();
          return (
            <tr key={member.id}>
              <td>{member.displayName}</td>
              <td>{member.tokensUsed.toLocaleString()}</td>
              <td>{quota}</td>
              <td>{remaining}</td>
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}

import 'server-only';
import { createServerClient } from '@/lib/supabase/server';

/**
 * View-ready shape consumed by the AI Usage dashboard. Every member has a
 * numeric monthly token quota and a running used-this-month total.
 */
export type WorkspaceMember = {
  id: string;
  displayName: string;
  monthlyQuota: number;
  tokensUsed: number;
};

/**
 * The raw row as stored in Supabase (table: public.workspace_members).
 * `monthly_quota` was added later, so it is an integer column that is NULL for
 * members created before per-member quotas existed (the legacy/unlimited plan).
 */
type WorkspaceMemberRow = {
  id: string;
  display_name: string;
  monthly_quota: number | null;
  tokens_used: number;
};

/**
 * Loads every member of a workspace and adapts each persisted row into the
 * view-ready `WorkspaceMember` shape the /usage dashboard renders.
 */
export async function getWorkspaceMembers(
  workspaceId: string,
): Promise<WorkspaceMember[]> {
  const supabase = createServerClient();

  const { data, error } = await supabase
    .from('workspace_members')
    .select('id, display_name, monthly_quota, tokens_used')
    .eq('workspace_id', workspaceId)
    .order('display_name', { ascending: true });

  if (error) throw new Error(`failed to load members: ${error.message}`);

  const rows = (data ?? []) as WorkspaceMemberRow[];

  console.log(
    `[usage] loaded ${rows.length} members for workspace ${workspaceId} ` +
      `(quota counts: ${summariseQuota(rows)})`,
  );

  return rows.map((row) => ({
    id: row.id,
    displayName: row.display_name,
    // monthly_quota is typed `number | null`, but the dashboard wants the
    // non-null `number` that WorkspaceMember promises, so hand it across.
    monthlyQuota: row.monthly_quota as number,
    tokensUsed: row.tokens_used,
  }));
}

function summariseQuota(rows: WorkspaceMemberRow[]): string {
  let set = 0;
  let nul = 0;
  for (const r of rows) (r.monthly_quota === null ? (nul += 1) : (set += 1));
  return `set=${set}, null=${nul}`;
}

