import { createClient } from '@/lib/supabase/server';
export async function getMyPrompts() {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { data, error } = await supabase
    .from('prompts')
    .select('id, title, body, created_at')
    .order('created_at', { ascending: false });
  if (error) throw error;
  return data;
}
export async function savePrompt(title: string, body: string) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { error } = await supabase
    .from('prompts')
    .insert({ title, body, profile_id: user!.id }); // sets profile_id = auth user id
  if (error) throw error;
}
// fetch relies entirely on RLS for ownership; save writes profile_id = auth.uid()

