import { getMyPrompts, savePrompt } from '@/lib/prompts';
import { revalidatePath } from 'next/cache';
export default async function PromptsPage() {
  const prompts = await getMyPrompts();
  async function add(formData: FormData) {
    'use server';
    await savePrompt(String(formData.get('title')), String(formData.get('body')));
    revalidatePath('/prompts');
  }
  return (
    <main>
      <form action={add}>
        <input name="title" placeholder="Title" required />
        <textarea name="body" placeholder="Prompt" required />
        <button type="submit">Save</button>
      </form>
      <ul>
        {prompts.map((p) => (
          <li key={p.id}><strong>{p.title}</strong><pre>{p.body}</pre></li>
        ))}
      </ul>
    </main>
  );
}
